import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function TakeTest() {
  const user = useSelector((state) => state.auth.user);
  const { testId } = useParams();
  const navigate = useNavigate();
  const [test, setTest] = useState(null);
  const [answers, setAnswers] = useState([]);
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState(null);

  useEffect(() => {
    if (user?.role === "student") {
      fetch(`http://localhost:3001/tests/${testId}`)
        .then((res) => res.json())
        .then((data) => {
          setTest(data);
          setAnswers(new Array(data.questions.length).fill(null));
        })
        .catch((error) => {
          toast.error("Ошибка загрузки теста");
          navigate("/courses");
        });
      // Check if test already submitted
      fetch(`http://localhost:3001/test_results?userId=${user.id}&testId=${testId}`)
        .then((res) => res.json())
        .then((data) => {
          if (data.length > 0) {
            setSubmitted(true);
            setScore(data[0].score);
            setAnswers(data[0].answers);
          }
        })
        .catch((error) => toast.error("Ошибка проверки результатов"));
    }
  }, [user, testId, navigate]);

  function handleAnswerChange(questionIndex, optionIndex) {
    const newAnswers = [...answers];
    newAnswers[questionIndex] = optionIndex;
    setAnswers(newAnswers);
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (answers.some((a) => a === null)) {
      toast.error("Ответьте на все вопросы!");
      return;
    }
    try {
      // Calculate score
      const correctAnswers = test.questions.filter((q, i) => q.correctAnswerIndex === answers[i]).length;
      const score = ((correctAnswers / test.questions.length) * 100).toFixed(2);
      const result = {
        userId: user.id,
        testId: parseInt(testId),
        answers,
        score: parseFloat(score),
        submittedAt: new Date().toISOString(),
      };
      const response = await fetch("http://localhost:3001/test_results", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(result),
      });
      if (response.ok) {
        setSubmitted(true);
        setScore(score);
        toast.success("Тест сдан!");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Вы сдали тест "${test.title}" с результатом ${score}%.`,
            createdAt: new Date().toISOString(),
          }),
        });
      } else {
        const errorData = await response.json();
        toast.error(`Не удалось сдать тест: ${errorData.message || "Ошибка сервера"}`);
      }
    } catch (error) {
      console.error("Submit test error:", error);
      toast.error("Сетевая ошибка при сдаче теста");
    }
  }

  if (user?.role !== "student") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  if (!test) {
    return <div className="container mt-5"><h1>Загрузка...</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">{test.title}</h1>
      <div className="card shadow">
        <div className="card-body">
          {submitted ? (
            <div>
              <h2>Результат: {score}%</h2>
              <p>Вы уже сдали этот тест.</p>
              <button className="btn btn-primary" onClick={() => navigate("/courses")}>
                Вернуться к курсам
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit}>
              {test.questions.map((question, qIndex) => (
                <div key={question.id} className="mb-4">
                  <h5>{qIndex + 1}. {question.text}</h5>
                  {question.options.map((option, oIndex) => (
                    <div key={oIndex} className="form-check">
                      <input
                        type="radio"
                        id={`q${qIndex}-o${oIndex}`}
                        name={`question-${qIndex}`}
                        className="form-check-input"
                        value={oIndex}
                        checked={answers[qIndex] === oIndex}
                        onChange={() => handleAnswerChange(qIndex, oIndex)}
                        disabled={submitted}
                      />
                      <label htmlFor={`q${qIndex}-o${oIndex}`} className="form-check-label">
                        {option}
                      </label>
                    </div>
                  ))}
                </div>
              ))}
              <button type="submit" className="btn btn-primary w-100" disabled={submitted}>
                Сдать тест
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

export default TakeTest;
